package com.example.rest_kafka_poc.service;import com.example.rest_kafka_poc.entity.EmployeeEntity;import com.google.gson.Gson;import org.springframework.beans.factory.annotation.Autowired;import org.springframework.context.annotation.Lazy;import org.springframework.kafka.annotation.KafkaListener;import org.springframework.kafka.core.KafkaTemplate;import org.springframework.stereotype.Service;import java.util.LinkedHashMap;import java.util.Map;@Servicepublic class EmployeeKafkaImpl implements EmployeeKafka {    private static final String TOPIC = "my-topic";    private static final String CONSUMER_GROUP = "consumer-my-group";    @Autowired    @Lazy    EmployeeServiceImpl employeeService;    @Autowired    private KafkaTemplate<String, String> kafkaTemplate;    @KafkaListener(topics = TOPIC, groupId = CONSUMER_GROUP)    public void read(String message) {        System.out.println("Message from the Kafka " + message);        String readMessage = "{" + message.substring(message.indexOf("(") + 1, message.indexOf(")")) + " }";        EmployeeEntity employee = new Gson().fromJson(readMessage, EmployeeEntity.class);        employeeService.createEmployee(employee);    }    public Boolean producer(String message) {        Map map = new LinkedHashMap<>();        map.getOrDefault("c", 0);        try {            kafkaTemplate.send(TOPIC, message).get();            return true;        } catch (Exception e) {            e.printStackTrace();            return false;        }    }}